CREATE TABLE IF NOT EXISTS reposts (devlog INT, "by" VARCHAR(50), created_at TIMESTAMP NOT NULL, "content" VARCHAR(4000) NULL, first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, CONSTRAINT pk_reposts PRIMARY KEY (devlog, "by"), CONSTRAINT fk_reposts_devlog__id FOREIGN KEY (devlog) REFERENCES posts(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_reposts_by__name FOREIGN KEY ("by") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_reposts_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);